import{_ as i,o as t,c as s,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"52. Higher Duties","description":"","frontmatter":{"title":"52. Higher Duties","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["wages","classifications","higher-duties","preliminary"]},"headers":[],"relativePath":"ebas/mspp/classification-salaries/52-higher-duties.md","filePath":"ebas/mspp/classification-salaries/52-higher-duties.md"}'),r={name:"ebas/mspp/classification-salaries/52-higher-duties.md"};function o(n,e,h,l,p,c){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="_52-higher-duties" tabindex="-1">52. Higher Duties <a class="header-anchor" href="#_52-higher-duties" aria-label="Permalink to &quot;52. Higher Duties&quot;">​</a></h1><p><strong>a.</strong> An Employee who is authorised to assume the duties of another Employee on a higher classification under this Agreement for a period of five or more consecutive working days shall be paid for the period for which he/she assumed such duties, at not less than the minimum rate prescribed for the classification applying to the Employee so relieved.</p><p><strong>b.</strong> Where an Employee is temporarily assigned duties of a higher classification for a total period of 12 months (in continuous or broken periods), the Employee will be entitled to move to the next pay point within the salary range for the higher classification.</p><p><strong>c.</strong> The Employee will be entitled to remuneration at this pay point in the event she/he is permanently reclassified to the higher level or during any subsequent period/s of temporary assignment to the higher classification until a further entitlement for pay point progression at the higher classification level is achieved.</p><p><strong>d.</strong> Higher duties service is not counted if it is beyond five years from the higher duty period.</p><p><strong>e.</strong> Provided however that where a Laboratory Manager is appointed in writing to assume the same administrative responsibilities as the Director or Pathologist in charge, for a period exceeding four weeks they shall be paid at the top incremental level for the classification with the addition of 31.5% of that increment.</p><p>Plain language terms: acting up, HDA, higher duties allowance.</p>',7)])])}const u=i(r,[["render",o]]);export{g as __pageData,u as default};
